import re
from pathlib import Path
from decimal import Decimal
import fitz, pytesseract
from PIL import Image

DOCS = Path('/app/documents')

invoice_terms = ['invoice', 'bill to', 'amount due', 'grand total', 'totalprice', 'vat [%]']
noninvoice_terms = ['stock report', 'purchase orders', 'inter-office', 'interoffice', 'correspondenc', 'assistant professor']

num_pattern = re.compile(r'(?<!\d)(?:\d{1,3}(?:[ .,]\d{3})+|\d+)(?:[.,]\d{1,2})?(?!\d)')

def extract_text(path: Path) -> str:
    if path.suffix.lower() == '.pdf':
        with fitz.open(path) as doc:
            return '\n'.join(page.get_text() for page in doc)
    return pytesseract.image_to_string(Image.open(path), config='--psm 6')

def norm_spaces(s: str) -> str:
    return re.sub(r'\s+', ' ', s.replace('\xa0', ' ')).strip()

def parse_decimal(token: str):
    s = token.strip()
    s = re.sub(r'[^\d,.-]', '', s.replace(' ', ''))
    if not s or not re.search(r'\d', s):
        return None
    if ',' in s and '.' in s:
        if s.rfind(',') > s.rfind('.'):
            s = s.replace('.', '').replace(',', '.')
        else:
            s = s.replace(',', '')
    elif ',' in s:
        parts = s.split(',')
        if len(parts[-1]) in (1, 2):
            s = ''.join(parts[:-1]).replace(',', '') + '.' + parts[-1]
        else:
            s = ''.join(parts)
    elif '.' in s:
        parts = s.split('.')
        if len(parts) > 2 and all(len(p) == 3 for p in parts[1:]):
            s = ''.join(parts)
    try:
        return Decimal(s)
    except Exception:
        return None

def amounts(line: str):
    vals = []
    for m in num_pattern.finditer(line):
        d = parse_decimal(m.group(0))
        if d is not None:
            vals.append(d)
    return vals

def classify(text: str) -> bool:
    low = text.lower()
    if any(t in low for t in invoice_terms):
        return True
    if any(t in low for t in noninvoice_terms):
        return False
    score = 0
    for t in ['invoice', 'seller:', 'client:', 'iban:', 'tax id:', 'bill to']:
        if t in low:
            score += 1
    return score >= 2

def extract_amounts(text: str):
    lines = [norm_spaces(ln) for ln in text.splitlines()]
    lines = [ln for ln in lines if ln]
    total_candidates = []
    amount_due_candidates = []
    vat_candidates = []
    for i, ln in enumerate(lines):
        low = ln.lower()
        nums = amounts(ln)
        next_nums = amounts(lines[i+1]) if i + 1 < len(lines) else []
        if 'tax id' in low:
            continue
        if re.search(r'\btotalprice\b', low):
            src = nums or next_nums
            if src:
                total_candidates.append(src[-1])
                if len(src) >= 3:
                    vat_candidates.append(src[-2])
            continue
        if re.search(r'\bamount due\b', low):
            src = nums or next_nums
            if src:
                amount_due_candidates.append(src[-1])
            continue
        if 'subtotal' in low:
            continue
        if re.search(r'\bgrand total\b', low) or re.search(r'\btotal\b', low):
            src = nums or next_nums
            if src:
                if len(src) >= 3:
                    vat_candidates.append(src[-2])
                    total_candidates.append(src[-1])
                else:
                    total_candidates.append(src[-1])
                continue
        if re.search(r'\b(vat|gst|tax)\b', low):
            src = nums or next_nums
            if src:
                if 'vat [%]' in low and len(src) >= 3:
                    vat_candidates.append(src[-2])
                else:
                    vat_candidates.append(src[-1])
    total_amount = total_candidates[-1] if total_candidates else (amount_due_candidates[-1] if amount_due_candidates else Decimal('0'))
    vat_amount = vat_candidates[-1] if vat_candidates else Decimal('0')
    return total_amount, vat_amount

for p in sorted(DOCS.iterdir()):
    txt = extract_text(p)
    inv = classify(txt)
    if inv:
        total, vat = extract_amounts(txt)
        print(p.name, 'invoice', total, vat)
    else:
        print(p.name, 'other')
